class Solution {
public:
    vector<int> w;
    Solution(vector<int>& w) : w(w) {

    }

    int pickIndex() {
        int sum = 0;
        for (int i = 0; i < w.size(); i++) {
            sum += w[i];
        }
        int target = rand() % sum;
        int cur = 0;
        for (int i = 0; i < w.size(); i++) {
            cur += w[i];
            if (target < cur) {
                return i;
            }
        }
        return w.size() - 1;
    }
};

